import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class HaircutStylesOfferParser implements IMessageParser
{
private _offerId: number = 0;
private _stylistId: number = 0;
private _stylistName: string = '';
private _price: number = 0;
private _baseFigure: string = '';

public flush(): boolean
{
this._offerId = 0;
this._stylistId = 0;
this._stylistName = '';
this._price = 0;
this._baseFigure = '';
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean
{
if(!wrapper) return false;

this._offerId = wrapper.readInt();
this._stylistId = wrapper.readInt();
this._stylistName = wrapper.readString() || '';
this._price = wrapper.readInt();
this._baseFigure = wrapper.readString() || '';
return true;
}

public get offerId(): number
{
return this._offerId;
}

public get stylistId(): number
{
return this._stylistId;
}

public get stylistName(): string
{
return this._stylistName;
}

public get price(): number
{
return this._price;
}

public get baseFigure(): string
{
return this._baseFigure;
}
}
